    pub fn trusted_dealer_setup(
        min_signers: u16,
        max_signers: u16,
    ) -> (BTreeMap<frost::Identifier, frost::keys::SecretShare>, frost::keys::PublicKeyPackage)
    {
        let rng: rand::prelude::ThreadRng = thread_rng();
        frost::keys::generate_with_dealer(
            max_signers,
            min_signers,
            frost::keys::IdentifierList::Default,
            rng,
        )
        .expect("valid key package")
    }

    // Util function to create a btc tx with random inputs and outputs as defined by fn params
    pub fn create_tx(num_inputs: usize) -> Transaction {
        // generate random 32 byte hash
        let mut rng = thread_rng();
        let mut tx_hash = [0u8; 32];
        rng.fill_bytes(&mut tx_hash);

        let mut out_points = vec![];
        let mut inputs = vec![];
        for _ in 0..num_inputs {
            let op = OutPoint::new(Txid::from_slice(&tx_hash).expect("valid txid"), 0);
            out_points.push(op);
            inputs.push(TxIn {
                previous_output: op,
                script_sig: ScriptBuf::new(),
                sequence: Sequence::MAX,
                witness: Default::default(),
            });
        }

        // Hardcoded one output
        let outputs = vec![TxOut {
            value: 1000,
            script_pubkey: Address::from_str("mrpkDJFJdNGA22FaxCWw6T9oXogXfHU1rh")
                .expect("valid address")
                .assume_checked()
                .script_pubkey(),
        }];
        Transaction { version: 2, lock_time: LockTime::ZERO, input: inputs, output: outputs }
    }

    pub fn create_psbt(num_inputs: usize) -> Psbt {
        let tx = create_tx(num_inputs);

        let weight = tx.weight();
        let fee = FEERATE * weight;
        let input_needed = fee.to_sat() + tx.output.iter().map(|o| o.value).sum::<u64>();
        let value_per_input = input_needed / num_inputs as u64 + 1;

        let mut psbt = Psbt::from_unsigned_tx(tx).expect("valid psbt");
        for i in 0..num_inputs {
            psbt.inputs[i].witness_utxo =
                Some(TxOut { value: value_per_input, script_pubkey: ScriptBuf::new() });
        }
        psbt
    }

